'use strict';
class NeighborhoodLookup{
static#instance=null;
#zipInput;
#select;
#savedOptions;
#notice=null;#generation=0;#abortController=new AbortController();#fetchController=null;
constructor(zipInput,select){
this.#zipInput=zipInput;
this.#select=select;
this.#savedOptions=[...select.children].map((child)=>child.cloneNode(true));
this.#zipInput.addEventListener('input',this.#handleInput,{signal:this.#abortController.signal});
if(/^\d{5}$/.test(zipInput.value.trim())){
this.#lookup();}}
static init(){
if(NeighborhoodLookup.#instance)return NeighborhoodLookup.#instance;
const zipInput=document.getElementById('zip_code');
const select=document.getElementById('neighborhood_id');
if(!zipInput||!select)return null;
return(NeighborhoodLookup.#instance=new NeighborhoodLookup(zipInput,select));}
destroy(){
this.#abortController.abort();
this.#fetchController?.abort();
NeighborhoodLookup.#instance=null;}#handleInput=()=>{
this.#lookup();};
async#lookup(){
const zip=this.#zipInput.value.trim();
const token=++this.#generation;
if(!/^\d{5}$/.test(zip)){
this.#hideNotice();
this.#restoreFullList();
return;}
this.#fetchController?.abort();
this.#fetchController=new AbortController();
try{
const res=await NT.fetch(`/api/neighborhoods/${encodeURIComponent(zip)}`,{
signal:this.#fetchController.signal,});
if(token!==this.#generation)return;
if(!res.ok){
this.#hideNotice();
this.#restoreFullList();
return;}
const neighborhoods=await res.json();
if(!neighborhoods.length){
this.#restoreFullList();
this.#showNotice();
return;}
this.#hideNotice();
const current=this.#select.value;
const grouped={};
for(const n of neighborhoods){
(grouped[n.city_name_nbh]??=[]).push(n);}
const fragment=document.createDocumentFragment();
const placeholder=document.createElement('option');
placeholder.value='';
placeholder.textContent='Select a neighborhood';
fragment.appendChild(placeholder);
for(const city of Object.keys(grouped).sort()){
const group=document.createElement('optgroup');
group.label=city;
for(const n of grouped[city]){
const opt=document.createElement('option');
opt.value=n.id_nbh;
opt.textContent=n.neighborhood_name_nbh;
opt.selected=String(n.id_nbh)===current;
group.appendChild(opt);}
fragment.appendChild(group);}
this.#select.replaceChildren(fragment);}catch(err){
if(err?.name==='AbortError')return;
if(token!==this.#generation)return;
NT.toast('Could not load neighborhoods for that ZIP code.','error');
this.#restoreFullList();}}#showNotice(){
if(this.#notice)return;
const group=this.#zipInput.closest('.form-group');
if(!group)return;
this.#notice=document.createElement('span');
this.#notice.id='zip-coverage-notice';
this.#notice.className='form-hint';
this.#notice.setAttribute('role','status');
this.#notice.setAttribute('data-coverage-warning','');
this.#notice.textContent='This ZIP code isn\u2019t in a supported neighborhood yet. You can still create an account, but tool sharing is limited to the Asheville and Hendersonville areas.';
group.appendChild(this.#notice);
const described=this.#zipInput.getAttribute('aria-describedby')??'';
if(!described.includes('zip-coverage-notice')){
this.#zipInput.setAttribute('aria-describedby',
[described,'zip-coverage-notice'].filter(Boolean).join(' '),);}}#hideNotice(){
if(!this.#notice)return;
const described=(this.#zipInput.getAttribute('aria-describedby')??'')
.replace('zip-coverage-notice','')
.trim();
this.#zipInput.setAttribute('aria-describedby',described||'');
if(!described)this.#zipInput.removeAttribute('aria-describedby');
this.#notice.remove();
this.#notice=null;}#restoreFullList(){
this.#select.replaceChildren(...this.#savedOptions.map((node)=>node.cloneNode(true)));}}
class PasswordToggle{
static#instance=null;
#fields;
#buttons=[];#abortController=new AbortController();
constructor(fields){
this.#fields=fields;
const{signal}=this.#abortController;
for(const input of fields){
const group=input.closest('.form-group');
if(!group)continue;
group.setAttribute('data-password-toggle','');
const btn=document.createElement('button');
btn.type='button';
btn.setAttribute('data-toggle-visibility','');
btn.setAttribute('aria-label','Show password');
const icon=document.createElement('i');
icon.className='fa-regular fa-eye';
icon.setAttribute('aria-hidden','true');
btn.appendChild(icon);
input.after(btn);
this.#buttons.push({btn,icon});
btn.addEventListener('click',this.#handleToggle,{signal});}
const form=fields[0].closest('form');
if(form){
form.addEventListener('submit',this.#handleSubmit,{signal});}}
static init(){
if(PasswordToggle.#instance)return PasswordToggle.#instance;
const fields=document.querySelectorAll('input[type="password"]');
if(!fields.length)return null;
return(PasswordToggle.#instance=new PasswordToggle(fields));}
destroy(){
this.#abortController.abort();
for(const{btn}of this.#buttons)btn.remove();
this.#buttons=[];
PasswordToggle.#instance=null;}#handleToggle=()=>{
const showing=this.#fields[0].type==='text';
const newType=showing?'password':'text';
const newIcon=showing?'fa-regular fa-eye':'fa-regular fa-eye-slash';
const newLabel=showing?'Show password':'Hide password';
for(const f of this.#fields)f.type=newType;
for(const b of this.#buttons){
b.icon.className=newIcon;
b.btn.setAttribute('aria-label',newLabel);}};#handleSubmit=()=>{
for(const input of this.#fields)input.type='password';};}
NeighborhoodLookup.init();
PasswordToggle.init();